import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Runtime and Tooling","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/runtime-and-tooling.md","filePath":"architecture/runtime-and-tooling.md"}'),l={name:"architecture/runtime-and-tooling.md"};function r(n,e,s,d,c,u){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="runtime-and-tooling" tabindex="-1">Runtime and Tooling <a class="header-anchor" href="#runtime-and-tooling" aria-label="Permalink to &quot;Runtime and Tooling&quot;">​</a></h1><p>The Vex repository is more than a compiler. The runtime and tools layer determines how code is linked, executed, tested, formatted, and surfaced in editors.</p><h2 id="runtime-layer" tabindex="-1">Runtime Layer <a class="header-anchor" href="#runtime-layer" aria-label="Permalink to &quot;Runtime Layer&quot;">​</a></h2><p>Runtime support lives primarily under <code>lib/runtime/</code>.</p><p>This layer includes infrastructure for:</p><ul><li>allocation and heap management</li><li>async and task runtime support</li><li>scheduler state</li><li>runtime symbols used by CLI execution paths</li><li>platform integration for native execution</li></ul><h2 id="execution-model" tabindex="-1">Execution Model <a class="header-anchor" href="#execution-model" aria-label="Permalink to &quot;Execution Model&quot;">​</a></h2><p>Vex compiles to native code ahead-of-time (AOT). Both <code>vex run</code> and <code>vex compile</code> produce native binaries via LLVM. <code>vex run</code> compiles to a temporary executable and runs it as a subprocess; <code>vex compile</code> produces a standalone binary.</p><p>The runtime is linked as a static library (<code>libvexruntime.a</code>) alongside the compiled Vex code. The system linker resolves all symbols at build time -- no runtime symbol registration is needed.</p><h2 id="cli-tooling" tabindex="-1">CLI Tooling <a class="header-anchor" href="#cli-tooling" aria-label="Permalink to &quot;CLI Tooling&quot;">​</a></h2><p><code>tools/vex-cli/</code> is the main developer-facing entry point.</p><p>Important commands:</p><ul><li><code>vex run</code></li><li><code>vex compile</code></li><li><code>vex test</code></li></ul><p>The CLI owns orchestration around:</p><ul><li>dependency resolution</li><li>compiler-driver invocation</li><li>linking</li><li>execution model selection</li><li>test discovery and execution</li></ul><h2 id="other-tooling" tabindex="-1">Other Tooling <a class="header-anchor" href="#other-tooling" aria-label="Permalink to &quot;Other Tooling&quot;">​</a></h2><p>The repository also contains:</p><ul><li><code>tools/vex-lsp/</code> for editor integration</li><li>formatter tooling</li><li>docs tooling and site generation</li></ul><p>These tools matter because they all depend on the same semantic model staying aligned with the compiler.</p><h2 id="why-this-layer-matters" tabindex="-1">Why This Layer Matters <a class="header-anchor" href="#why-this-layer-matters" aria-label="Permalink to &quot;Why This Layer Matters&quot;">​</a></h2><p>Many user-facing “language” issues are actually toolchain or runtime issues:</p><ul><li>link mode differences</li><li>symbol registration gaps</li><li>runtime state constraints</li><li>test-runner discovery assumptions</li><li>editor/compiler semantic drift</li></ul><p>Understanding this layer makes debugging much faster.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/docs/references/vex-cli-reference">CLI Reference</a></li><li><a href="/docs/references/vex-test-reference">Test Reference</a></li><li><a href="/docs/architecture/compiler-pipeline">Compiler Pipeline</a></li></ul>',25)])])}const p=i(l,[["render",r]]);export{h as __pageData,p as default};
